    private DataRecord parseRecord(Element recordElement) throws Exception {
        DataRecord record = new DataRecord();
        
        String id = getElementTextContent(recordElement, "id");
        String name = getElementTextContent(recordElement, "name");
        String type = getElementTextContent(recordElement, "type");
        String value = getElementTextContent(recordElement, "value");
        String timestamp = getElementTextContent(recordElement, "timestamp");
        
        record.setId(id);
        record.setName(name);
        record.setType(type);
        record.setValue(value);
        record.setTimestamp(timestamp);
        
        NodeList attributeNodes = recordElement.getElementsByTagName("attribute");
        Map<String, String> attributes = new HashMap<>();
        
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Node attrNode = attributeNodes.item(i);
            if (attrNode.getNodeType() == Node.ELEMENT_NODE) {
                Element attrElement = (Element) attrNode;
                String key = attrElement.getAttribute("key");
                String val = attrElement.getTextContent();
                attributes.put(key, val);
            }
        }
        
        record.setAttributes(attributes);
        
        return record;
    }

    private EntityData parseEntity(Element entityElement) throws Exception {
        EntityData entity = new EntityData();
        
        String id = entityElement.getAttribute("id");
        String type = entityElement.getAttribute("type");
        
        entity.setId(id);
        entity.setType(type);
        
        Map<String, Object> properties = new HashMap<>();
        
        NodeList propertyNodes = entityElement.getElementsByTagName("property");
        for (int i = 0; i < propertyNodes.getLength(); i++) {
            Node propNode = propertyNodes.item(i);
            if (propNode.getNodeType() == Node.ELEMENT_NODE) {
                Element propElement = (Element) propNode;
                String name = propElement.getAttribute("name");
                String value = propElement.getTextContent();
                properties.put(name, value);
            }
        }
        
        entity.setProperties(properties);
        
        List<String> relatedEntities = new ArrayList<>();
        NodeList relationNodes = entityElement.getElementsByTagName("relation");
        for (int i = 0; i < relationNodes.getLength(); i++) {
            Node relNode = relationNodes.item(i);
            if (relNode.getNodeType() == Node.ELEMENT_NODE) {
                Element relElement = (Element) relNode;
                String refId = relElement.getAttribute("refId");
                relatedEntities.add(refId);
            }
        }
        
        entity.setRelatedEntities(relatedEntities);
        
        NodeList childNodes = entityElement.getElementsByTagName("child");
        List<EntityData> children = new ArrayList<>();
        
        for (int i = 0; i < childNodes.getLength(); i++) {
            Node childNode = childNodes.item(i);
            if (childNode.getNodeType() == Node.ELEMENT_NODE && 
                childNode.getParentNode().equals(entityElement)) {
                EntityData childEntity = parseEntity((Element) childNode);
                children.add(childEntity);
            }
        }
        
        entity.setChildren(children);
        
        return entity;
    }

    private void processEntityRelationships(Map<String, EntityData> entities) {
        for (EntityData entity : entities.values()) {
            for (String relatedId : entity.getRelatedEntities()) {
                EntityData relatedEntity = entities.get(relatedId);
                if (relatedEntity != null) {
                    entity.getResolvedRelations().add(relatedEntity);
                }
            }
        }
    }

